// /frontend/src/lib/communityApi.js
const BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

async function req(path, { method = "GET", body } = {}) {
  const res = await fetch(`${BASE}${path}`, {
    method,
    headers: { "Content-Type": "application/json" },
    body: body ? JSON.stringify(body) : undefined,
    credentials: "include", // okay if you later add auth cookies
  });
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`HTTP ${res.status} ${res.statusText}: ${text || path}`);
  }
  return res.json();
}

/** Feed: GET /api/community/feed?city=&limit=&cursor=  */
export function fetchFeed({ city = "", limit = 20, cursor = "" } = {}) {
  const q = new URLSearchParams();
  if (city) q.set("city", city);
  if (limit) q.set("limit", String(limit));
  if (cursor) q.set("cursor", cursor);
  return req(`/api/community/feed?${q.toString()}`);
}

/** Create question: POST /api/community/questions  body: {city, text} */
export function createQuestion({ city = "", text = "" }) {
  return req(`/api/community/questions`, {
    method: "POST",
    body: { city, text },
  });
}

/** Reply: POST /api/community/questions/:id/replies  body: {text} */
export function replyToQuestion({ questionId, text }) {
  return req(`/api/community/questions/${encodeURIComponent(questionId)}/replies`, {
    method: "POST",
    body: { text },
  });
}

/** Vote: POST /api/community/vote  body: {type: "question" | "reply", id, delta: +1 | -1} */
export function vote({ type = "question", id, delta = 1 }) {
  return req(`/api/community/vote`, {
    method: "POST",
    body: { type, id, delta },
  });
}

/** Report: POST /api/community/report  body: {type, id, reason} */
export function report({ type = "question", id, reason = "" }) {
  return req(`/api/community/report`, {
    method: "POST",
    body: { type, id, reason },
  });
}

/** Optional repost route: POST /api/community/repost  body: {id} */
async function repost({ id }) {
  return req(`/api/community/repost`, { method: "POST", body: { id } });
}

/* ---- Aliases expected by components ---- */
function list(args) { return fetchFeed(args); }
function create(args) { return createQuestion(args); }
function like({ id, type = "question" }) { return vote({ id, type, delta: 1 }); }
function reply({ questionId, text }) { return replyToQuestion({ questionId, text }); }

const api = {
  // named
  fetchFeed, createQuestion, replyToQuestion, vote, report,
  // aliases
  list, create, like, reply, repost,
};

export default api;
export { list, create, like, reply, repost };
